import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges) {
        List<List<long[]>> adj = new ArrayList<>();
        for (long i = 0; i < n; i++) {
            adj.add(new ArrayList<>());
        }
        for (long[] edge : edges) {
            long u = edge[0];
            long v = edge[1];
            long s = edge[2];
            long e = edge[3];
            adj.get((int) u).add(new long[]{v, s, e});
        }

        long[] dist = new long[(int) n];
        for (int i = 0; i < n; i++) {
            dist[i] = Long.MAX_VALUE;
        }
        dist[0] = 0;

        PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[0], b[0]));
        pq.offer(new long[]{0, 0});

        while (!pq.isEmpty()) {
            long[] current = pq.poll();
            long time = current[0];
            long u = current[1];

            if (u == n - 1) {
                return time;
            }

            if (time > dist[u]) {
                continue;
            }

            for (long[] edge : adj.get((int) u)) {
                long v = edge[0];
                long s = edge[1];
                long e = edge[2];

                long earliest = Math.max(time, s);
                if (earliest > e) {
                    continue;
                }

                long arrival = earliest + 1;
                if (arrival < dist[v]) {
                    dist[v] = arrival;
                    pq.offer(new long[]{arrival, v});
                }
            }
        }

        return -1;
    }
}
